```javascript
// src/services/replyDraftEngine.js
const { OpenAI } = require('openai');
const languageDetector = require('./languageDetector');
const emailClassifier = require('./emailClassifier');

class ReplyDraftEngine {
  constructor() {
    this.openai = new OpenAI({
      apiKey: process.env.OPENAI_API_KEY,
    });
  }

  async processEmail(email) {
    // Step 1: Check if actionable
    const isActionable = await emailClassifier.isActionable(email);
    if (!isActionable) {
      return null;
    }

    // Step 2: Detect language
    const language = await languageDetector.detect(email.body + ' ' + email.subject);

    // Step 3: Determine reply scope
    const scope = this.determineReplyScope(email);

    // Step 4: Generate reply options
    const replyOptions = await this.generateReplyOptions(email, language, scope);

    // Step 5: Store in database
    const { ApprovalRequest } = require('../models/approvalRequest');
    const request = await ApprovalRequest.create({
      emailId: email.id,
      userId: email.userId,
      language: language,
      replyOptions: replyOptions,
      metadata: {
        classificationConfidence: isActionable.confidence,
        detectedLanguage: language,
        originalRecipients: {
          to: email.to,
          cc: email.cc || []
        }
      }
    });

    return request;
  }

  determineReplyScope(email) {
    const totalRecipients = (email.to?.length || 0) + (email.cc?.length || 0);

    // Reply all if multiple recipients or if email contains group indicators
    const groupIndicators = ['team', 'everyone', 'all', 'grupo', 'todos', 'equipe'];
    const hasGroupContext = groupIndicators.some(word => 
      email.body.toLowerCase().includes(word) || 
      email.subject.toLowerCase().includes(word)
    );

    if (totalRecipients > 1 || hasGroupContext) {
      return {
        type: 'reply_all',
        recipients: [...(email.to || []), ...(email.cc || [])],
        reasoning: totalRecipients > 1 ? 'multiple_recipients' : 'group_context'
      };
    }

    return {
      type: 'reply',
      recipients: [email.from],
      reasoning: 'single_recipient'
    };
  }

  async generateReplyOptions(email, language, scope) {
    const prompt = this.buildPrompt(email, language, scope);

    try {
      const response = await this.openai.chat.completions.create({
        model: "gpt-4-turbo-preview",
        messages: [
          {
            role: "system",
            content: this.getSystemPrompt(language)
          },
          {
            role: "user",
            content: prompt
          }
        ],
        temperature: 0.7,
        max_tokens: 1500,
        response_format: { type: "json_object" }
      });

      const content = response.choices[0].message.content;
      const parsed = JSON.parse(content);

      // Add metadata to each option
      return parsed.replies.map((reply, index) => ({
        id: `opt-${Date.now()}-${index}`,
        content: reply.content,
        tone: reply.tone || 'neutral',
        scope: scope.type,
        recipients: scope.recipients,
        estimatedReadTime: this.estimateReadTime(reply.content),
        confidence: reply.confidence || 0.9
      }));

    } catch (error) {
      console.error('Error generating replies:', error);
      // Fallback to template-based generation
      return this.generateFallbackReplies(email, language, scope);
    }
  }

  buildPrompt(email, language, scope) {
    const scopeInstruction = scope.type === 'reply_all' 
      ? 'This is a REPLY ALL scenario - maintain inclusive tone for group communication.'
      : 'This is a direct reply scenario.';

    const languageInstruction = language === 'pt' 
      ? 'Write responses in Portuguese (Brazilian).'
      : 'Write responses in English.';

    return `
Analyze this email and generate 3 reply options with different tones.

Email Subject: ${email.subject}
Email From: ${email.from}
Email Body: ${email.body}

${scopeInstruction}
${languageInstruction}

Generate:
1. Professional/Formal option
2. Friendly/Balanced option  
3. Brief/Direct option

Return JSON format:
{
  "replies": [
    {
      "content": "Full reply text including greeting and sign-off",
      "tone": "professional|friendly|brief",
      "confidence": 0.95
    }
  ]
}

Guidelines:
- Match the sender's language style and formality level
- Address all questions or action items in the original email
- Include appropriate greeting and closing
- For reply_all, ensure tone is appropriate for all recipients
`;
  }

  getSystemPrompt(language) {
    const basePrompt = `You are an expert email assistant specializing in drafting contextual, appropriate email replies.`;

    if (language === 'pt') {
      return `${basePrompt} You understand Brazilian business etiquette and Portuguese language nuances.`;
    }
    return `${basePrompt} You understand professional English communication standards.`;
  }

  generateFallbackReplies(email, language, scope) {
    const isReplyAll = scope.type === 'reply_all';

    if (language === 'pt') {
      return [
        {
          id: `fallback-1-${Date.now()}`,
          content: `Prezado(a),\n\nAgradeço seu email. Analisarei o conteúdo e retornarei em breve.\n\nAtenciosamente,\n[Seu Nome]`,
          tone: 'formal',
          scope: scope.type,
          recipients: scope.recipients,
          isFallback: true
        },
        {
          id: `fallback-2-${Date.now()}`,
          content: `Oi,\n\nRecebi sua mensagem. Podemos conversar sobre isso ${isReplyAll ? 'em breve' : 'na próxima reunião'}?\n\nAbs,\n[Seu Nome]`,
          tone: 'friendly',
          scope: scope.type,
          recipients: scope.recipients,
          isFallback: true
        }
      ];
    }

    return [
      {
        id: `fallback-1-${Date.now()}`,
        content: `Dear Sir/Madam,\n\nThank you for your email. I will review the contents and get back to you shortly.\n\nBest regards,\n[Your Name]`,
        tone: 'formal',
        scope: scope.type,
        recipients: scope.recipients,
        isFallback: true
      },
      {
        id: `fallback-2-${Date.now()}`,
        content: `Hi,\n\nThanks for reaching out. Can we discuss this ${isReplyAll ? 'as a group' : 'in our next meeting'}?\n\nBest,\n[Your Name]`,
        tone: 'friendly',
        scope: scope.type,
        recipients: scope.recipients,
        isFallback: true
      }
    ];
  }

  estimateReadTime(text) {
    const wordsPerMinute = 200;
    const wordCount = text.split(/\s+/).length;
    return Math.ceil(wordCount / wordsPerMinute);
  }
}

module.exports = new ReplyDraftEngine();
```

