// src/services/languageDetector.js
const franc = require('franc');
const iso6393 = require('iso-639-3');

class LanguageDetector {
  async detect(text) {
    if (!text || text.length < 10) return 'en';

    // Use franc for primary detection
    const detectedCode = franc(text);

    // Map to our supported languages (en/pt)
    const langMap = {
      'eng': 'en',
      'por': 'pt'
    };

    // Check for Portuguese indicators if franc is uncertain
    if (detectedCode === 'und' || detectedCode === 'spa') {
      const ptIndicators = ['olá', 'obrigado', 'atenciosamente', 'prezado', 'caro', 'você', 'são', 'muito'];
      const textLower = text.toLowerCase();
      const ptScore = ptIndicators.filter(word => textLower.includes(word)).length;

      if (ptScore >= 2) return 'pt';
    }

    return langMap[detectedCode] || 'en';
  }

  getLanguageName(code) {
    return code === 'pt' ? 'Portuguese' : 'English';
  }
}

module.exports = new LanguageDetector();
