### Email Classifier

```javascript
// src/services/emailClassifier.js
class EmailClassifier {
  async isActionable(email) {
    // Skip automated emails
    if (this.isAutomated(email)) {
      return { actionable: false, confidence: 0.99 };
    }

    // Check for action items
    const actionIndicators = [
      'please', 'por favor', 'could you', 'poderia', 'need you to', 'preciso que',
      'action required', 'ação necessária', 'deadline', 'prazo', 'urgent', 'urgente',
      'question', 'pergunta', 'follow up', 'seguimento', 'meeting', 'reunião'
    ];

    const text = (email.subject + ' ' + email.body).toLowerCase();
    const matches = actionIndicators.filter(indicator => text.includes(indicator));

    // Check for questions (indicates need for reply)
    const hasQuestion = text.includes('?') || 
                       text.includes('pode ') || 
                       text.includes('can you');

    const score = matches.length + (hasQuestion ? 2 : 0);

    return {
      actionable: score >= 2,
      confidence: Math.min(0.5 + (score * 0.1), 0.95),
      indicators: matches,
      hasQuestion
    };
  }

  isAutomated(email) {
    const autoIndicators = [
      'no-reply', 'noreply', 'do-not-reply', 'automated', 'notification',
      'newsletter', 'marketing', 'unsubscribe', 'system', 'alert'
    ];

    const fromLower = email.from.toLowerCase();
    return autoIndicators.some(ind => fromLower.includes(ind)) || 
           email.headers?.['X-Auto-Response-Suppress'];
  }
}

module.exports = new EmailClassifier();
