```javascript
// src/models/approvalRequest.js
const { Pool } = require('pg');
const pool = new Pool({
  connectionString: process.env.DATABASE_URL
});

class ApprovalRequest {
  static async create(data) {
    const query = `
      INSERT INTO approval_requests 
      (email_id, user_id, language, reply_options, metadata, status)
      VALUES ($1, $2, $3, $4, $5, 'pending')
      RETURNING *
    `;

    const values = [
      data.emailId,
      data.userId,
      data.language,
      JSON.stringify(data.replyOptions),
      JSON.stringify(data.metadata || {})
    ];

    const result = await pool.query(query, values);
    return this.fromRow(result.rows[0]);
  }

  static async findByUser(userId, status = 'pending') {
    const query = `
      SELECT ar.*, e.subject, e.from, e.body, e.received_at
      FROM approval_requests ar
      JOIN emails e ON ar.email_id = e.id
      WHERE ar.user_id = $1 AND ar.status = $2
      ORDER BY ar.created_at DESC
    `;

    const result = await pool.query(query, [userId, status]);
    return result.rows.map(row => this.fromRow(row));
  }

  static async updateStatus(id, status, selectedOptionId = null) {
    const query = `
      UPDATE approval_requests 
      SET status = $1, 
          selected_option_id = $2,
          responded_at = NOW()
      WHERE id = $3
      RETURNING *
    `;

    const result = await pool.query(query, [status, selectedOptionId, id]);
    return this.fromRow(result.rows[0]);
  }

  static fromRow(row) {
    return {
      id: row.id,
      emailId: row.email_id,
      userId: row.user_id,
      status: row.status,
      language: row.language,
      replyOptions: typeof row.reply_options === 'string' 
        ? JSON.parse(row.reply_options) 
        : row.reply_options,
      selectedOptionId: row.selected_option_id,
      createdAt: row.created_at,
      updatedAt: row.updated_at,
      metadata: typeof row.metadata === 'string' 
        ? JSON.parse(row.metadata) 
        : row.metadata,
      // Joined fields
      emailSubject: row.subject,
      emailFrom: row.from,
      emailBody: row.body,
      receivedAt: row.received_at
    };
  }
}

module.exports = { ApprovalRequest };
